SELECT ?actor ?actorLabel WHERE {
  ?show wdt:P345 "tt7560442" .
  ?show p:P161/ps:P161 ?actor .
  ?show p:P161/pq:P453 ?characterRole .
  ?characterRole rdfs:label "Simone Anders"@en .
  OPTIONAL { ?actor rdfs:label ?actorLabel . FILTER(LANG(?actorLabel) = "en") }
}
LIMIT 1

